import ast
import operator


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.
    """
    # Define safe evaluation environment
    def safe_eval(node, env):
        if isinstance(node, ast.Expression):
            return safe_eval(node.body, env)
        elif isinstance(node, ast.Constant):  # Python 3.8+
            return node.value
        elif isinstance(node, ast.Str):  # For older Python versions
            return node.s
        elif isinstance(node, ast.Num):  # For older Python versions
            return node.n
        elif isinstance(node, ast.Name):
            if node.id == 'input_data':
                return env.get('input_data')
            else:
                raise ValueError(f"Access to variable '{node.id}' is not allowed")
        elif isinstance(node, ast.Dict):
            keys = [safe_eval(k, env) for k in node.keys]
            values = [safe_eval(v, env) for v in node.values]
            return {k: v for k, v in zip(keys, values)}
        elif isinstance(node, ast.List):
            return [safe_eval(item, env) for item in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(safe_eval(item, env) for item in node.elts)
        elif isinstance(node, ast.Subscript):  # Handling indexing like input_data['key']
            container = safe_eval(node.value, env)
            key = safe_eval(node.slice, env)
            return container[key]
        elif isinstance(node, ast.Index):  # For older Python versions
            return safe_eval(node.value, env)
        elif isinstance(node, ast.Slice):
            lower = safe_eval(node.lower, env) if node.lower else None
            upper = safe_eval(node.upper, env) if node.upper else None
            step = safe_eval(node.step, env) if node.step else None
            return slice(lower, upper, step)
        elif isinstance(node, ast.Compare):
            left = safe_eval(node.left, env)
            results = []
            for op, comparator in zip(node.ops, node.comparators):
                right = safe_eval(comparator, env)
                results.append(_eval_op(op, left, right))
                left = right
            return all(results)
        elif isinstance(node, ast.BoolOp):
            values = [safe_eval(value, env) for value in node.values]
            if isinstance(node.op, ast.And):
                return all(values)
            elif isinstance(node.op, ast.Or):
                return any(values)
        elif isinstance(node, ast.UnaryOp):
            operand = safe_eval(node.operand, env)
            return _eval_unary_op(node.op, operand)
        elif isinstance(node, ast.BinOp):
            left = safe_eval(node.left, env)
            right = safe_eval(node.right, env)
            return _eval_op(node.op, left, right)
        elif isinstance(node, ast.Attribute):
            # Only allow attribute access on safe objects
            obj = safe_eval(node.value, env)
            if hasattr(obj, node.attr) and not node.attr.startswith('_'):
                return getattr(obj, node.attr)
            else:
                raise ValueError(f"Attribute access to '{node.attr}' is not allowed")
        else:
            raise ValueError(f"Unsupported operation: {type(node)}")

    def _eval_op(op, left, right):
        ops = {
            ast.Add: operator.add,
            ast.Sub: operator.sub,
            ast.Mult: operator.mul,
            ast.Div: operator.truediv,
            ast.Mod: operator.mod,
            ast.Pow: operator.pow,
            ast.FloorDiv: operator.floordiv,
            ast.Eq: operator.eq,
            ast.NotEq: operator.ne,
            ast.Lt: operator.lt,
            ast.LtE: operator.le,
            ast.Gt: operator.gt,
            ast.GtE: operator.ge,
            ast.Is: operator.is_,
            ast.IsNot: operator.is_not,
            ast.In: lambda x, y: x in y,
            ast.NotIn: lambda x, y: x not in y
        }
        if type(op) in ops:
            return ops[type(op)](left, right)
        else:
            raise ValueError(f"Unsupported operator: {type(op)}")

    def _eval_unary_op(op, operand):
        unary_ops = {
            ast.UAdd: operator.pos,
            ast.USub: operator.neg,
            ast.Not: operator.not_
        }
        if type(op) in unary_ops:
            return unary_ops[type(op)](operand)
        else:
            raise ValueError(f"Unsupported unary operator: {type(op)}")

    try:
        # Parse the expression safely
        parsed_expr = ast.parse(transform_map_expr, mode='eval')

        # Create environment with input_data accessible
        env = {'input_data': input_data}

        # Evaluate the expression safely
        result = safe_eval(parsed_expr, env)

        # Ensure the result is a dictionary
        if not isinstance(result, dict):
            raise ValueError("Expression must evaluate to a dictionary")

        return result
    except Exception as e:
        raise ValueError(f"Invalid expression: {str(e)}")

