        A new dictionary with transformed data according to the expression.
    """
    # Parse the expression safely using AST
    try:
        parsed_ast = ast.parse(transform_map_expr.strip(), mode='eval')
    except SyntaxError:
        raise ValueError(f"Invalid expression syntax: {transform_map_expr}")

    # Evaluate the AST in a restricted environment
    result = _safe_eval_node(parsed_ast.body, {'input_data': input_data})

    # Ensure the result is a dictionary
    if not isinstance(result, dict):
        raise TypeError("Expression must evaluate to a dictionary")

    return result


def _safe_eval_node(node, variables):
    """Safely evaluate an AST node with allowed operations only."""

    # Define allowed binary operations
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.FloorDiv: operator.floordiv,
        ast.BitAnd: operator.and_,
        ast.BitOr: operator.or_,
        ast.BitXor: operator.xor,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
    }

    # Define allowed unary operations
    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
        ast.Not: operator.not_,
        ast.Invert: operator.inv,
    }

    # Define allowed comparison operations
    cmp_ops = {
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.Is: operator.is_,
        ast.IsNot: operator.is_not,
        ast.In: lambda a, b: a in b,
        ast.NotIn: lambda a, b: a not in b,
    }

    if isinstance(node, ast.Expression):
        return _safe_eval_node(node.body, variables)

    elif isinstance(node, ast.Constant):  # For Python 3.8+
        return node.value

    elif isinstance(node, ast.Num):  # For older Python versions
        return node.n

    elif isinstance(node, ast.Str):  # For older Python versions
        return node.s

    elif isinstance(node, ast.NameConstant):  # For True, False, None in older Python
        return node.value

    elif isinstance(node, ast.Name):
        if node.id in variables:
            return variables[node.id]
        else:
            raise NameError(f"Name '{node.id}' is not defined")

    elif isinstance(node, ast.Dict):
        keys = [_safe_eval_node(k, variables) for k in node.keys]
        values = [_safe_eval_node(v, variables) for v in node.values]
        return dict(zip(keys, values))

    elif isinstance(node, ast.List):
        return [_safe_eval_node(item, variables) for item in node.elts]

    elif isinstance(node, ast.Tuple):
        return tuple(_safe_eval_node(item, variables) for item in node.elts)

    elif isinstance(node, ast.BinOp):
        left = _safe_eval_node(node.left, variables)
        right = _safe_eval_node(node.right, variables)
        op = bin_ops.get(type(node.op))
        if op is None:
            raise ValueError(f"Unsupported binary operation: {type(node.op)}")
        return op(left, right)

    elif isinstance(node, ast.UnaryOp):
        operand = _safe_eval_node(node.operand, variables)
        op = unary_ops.get(type(node.op))
        if op is None:
            raise ValueError(f"Unsupported unary operation: {type(node.op)}")
        return op(operand)

    elif isinstance(node, ast.Compare):
        left = _safe_eval_node(node.left, variables)
        # Handle multiple comparisons like 'a < b < c'
        results = []
        for i, (op, comparator) in enumerate(zip(node.ops, node.comparators)):
            right = _safe_eval_node(comparator, variables)
            cmp_func = cmp_ops.get(type(op))
            if cmp_func is None:
                raise ValueError(f"Unsupported comparison operation: {type(op)}")
            results.append(cmp_func(left, right))
            left = right

        return all(results)

    elif isinstance(node, ast.BoolOp):
        values = [_safe_eval_node(value, variables) for value in node.values]
        if isinstance(node.op, ast.And):
            result = values[0]
            for val in values[1:]:
                result = result and val
            return result
        elif isinstance(node.op, ast.Or):
            result = values[0]
            for val in values[1:]:
                result = result or val
            return result
        else:
            raise ValueError(f"Unsupported boolean operation: {type(node.op)}")

    elif isinstance(node, ast.Subscript):
        obj = _safe_eval_node(node.value, variables)
        key = _safe_eval_node(node.slice, variables)
        return obj[key]

    elif isinstance(node, ast.Index):  # For older Python versions
        return _safe_eval_node(node.value, variables)

    elif isinstance(node, ast.Slice):
        lower = _safe_eval_node(node.lower, variables) if node.lower else None
        upper = _safe_eval_node(node.upper, variables) if node.upper else None
        step = _safe_eval_node(node.step, variables) if node.step else None
        return slice(lower, upper, step)

    else:
        raise ValueError(f"Unsupported operation: {type(node)}")
